@namespace Lumeo

@{
    var context = new TimelineContext(Orientation, Animated, ActiveIndex, _lastActiveIndex, _replayKey, this, Layout);
}

<div class="@CssClass" role="list" @attributes="AdditionalAttributes">
    <CascadingValue Value="context" IsFixed="false">
        @ChildContent
    </CascadingValue>
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public Lumeo.Orientation Orientation { get; set; } = Lumeo.Orientation.Vertical;

    /// <summary>
    /// When true, each <see cref="TimelineItem"/> fades+translates in with a
    /// staggered delay, the active indicator pulses, and connector segments
    /// draw themselves as the active step advances. Default is <c>false</c>.
    /// </summary>
    [Parameter] public bool Animated { get; set; }

    /// <summary>
    /// Visual arrangement of the items:
    /// <list type="bullet">
    /// <item><see cref="TimelineLayout.Default"/> — all items stacked on one
    /// side of the rail (the classic single-column timeline).</item>
    /// <item><see cref="TimelineLayout.Alternate"/> — items zig-zag to either
    /// side of a centered rail (even indices on the left, odd on the right).
    /// Only applies to vertical orientation; horizontal falls back to
    /// Default.</item>
    /// </list>
    /// </summary>
    [Parameter] public TimelineLayout Layout { get; set; } = TimelineLayout.Default;

    /// <summary>
    /// When set AND <see cref="Animated"/> is true, drives the active-dot
    /// progression: items with index &lt; ActiveIndex render as "completed"
    /// (solid primary), the item at ActiveIndex pulses, later items are
    /// pending (muted). Connectors up to the active index draw themselves.
    /// Use together with <see cref="ActiveIndexChanged"/> for two-way binding.
    /// </summary>
    [Parameter] public int? ActiveIndex { get; set; }

    /// <summary>Two-way binding callback for <see cref="ActiveIndex"/>.</summary>
    [Parameter] public EventCallback<int> ActiveIndexChanged { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Identity-keyed item registry (mirrors Steps #244). Each TimelineItem
    // registers once and reads its index back, so the index stays stable across
    // independent child re-renders and the alternate layout assigns a
    // deterministic side per item.
    private readonly List<TimelineItem> _items = new();

    // Track the previous ActiveIndex so children can tell whether THEIR
    // connector should re-animate on this parameter change. `_replayKey`
    // is bumped on every change so @key can force a re-render of affected
    // connector elements.
    private int? _lastActiveIndex;
    private int _replayKey;

    internal void RegisterItem(TimelineItem item)
    {
        if (!_items.Contains(item))
            _items.Add(item);
    }

    internal void UnregisterItem(TimelineItem item) => _items.Remove(item);

    internal int GetItemIndex(TimelineItem item)
    {
        var idx = _items.IndexOf(item);
        return idx < 0 ? 0 : idx;
    }

    protected override void OnParametersSet()
    {
        if (ActiveIndex != _lastActiveIndex)
        {
            _replayKey++;
            _lastActiveIndex = ActiveIndex;
        }
    }

    private bool IsAlternate => Layout == TimelineLayout.Alternate && Orientation == Lumeo.Orientation.Vertical;

    private string CssClass => Orientation switch
    {
        Lumeo.Orientation.Horizontal => Cx.Merge("flex flex-row items-start", Class),
        // Alternate vs. standard vertical share the same parent flex container;
        // the left/right split is decided per-item, not here.
        _ => Cx.Merge("flex flex-col", Class)
    };

    /// <summary>Visual arrangement for <see cref="Timeline"/> items.</summary>
    public enum TimelineLayout
    {
        /// <summary>All items on one side of the rail (default single column).</summary>
        Default,
        /// <summary>Items alternate to either side of a centered rail (vertical only).</summary>
        Alternate
    }

    public record TimelineContext(Lumeo.Orientation Orientation, bool Animated, int? ActiveIndex, int? PreviousActiveIndex, int ReplayKey, Timeline Parent, TimelineLayout Layout)
    {
        public TimelineContext(Lumeo.Orientation Orientation) : this(Orientation, false, null, null, 0, default!, TimelineLayout.Default) { }

        /// <summary>True when the alternate (zig-zag) layout is in effect —
        /// alternate is meaningful only on the vertical axis.</summary>
        public bool IsAlternate => Layout == TimelineLayout.Alternate && Orientation == Lumeo.Orientation.Vertical;
    }
}

@namespace Lumeo
@implements IDisposable

@{
    // Re-read the stable registry index every render (mirrors Steps #244) so it
    // stays correct when items are added/removed — and so the alternate layout
    // assigns a deterministic left/right side per item.
    _index = Context?.Parent is not null ? Context.Parent.GetItemIndex(this) : 0;
    var isAlternate = Context?.IsAlternate == true;
    var sideRight = isAlternate && (_index % 2 == 1);
}

@if (Context?.Orientation == Lumeo.Orientation.Horizontal)
{
    <div class="@HorizontalCssClass" style="@AnimationStyle" role="listitem" aria-current="@ItemAriaCurrent" aria-label="@ItemAriaLabel" @attributes="AdditionalAttributes">
        <div class="flex flex-col items-center">
            <div class="@DotClasses">
                @if (IconContent is not null)
                {
                    @IconContent
                }
                else
                {
                    <div class="h-2.5 w-2.5 rounded-[calc(var(--radius)*2)] @DotInnerFillClass"></div>
                }
            </div>
            <div class="mt-2 flex flex-col items-center text-center">
                @ContentBlock
            </div>
        </div>
        <div class="@HorizontalConnectorClasses" @key="@($"tl-h-{_index}-{ConnectorState}")"></div>
    </div>
}
else if (isAlternate)
{
    @* Vertical alternate (zig-zag): a centered rail with the content on the
       left for even indices and the right for odd ones. *@
    <div class="@AlternateCssClass" style="@AnimationStyle" role="listitem" aria-current="@ItemAriaCurrent" aria-label="@ItemAriaLabel" @attributes="AdditionalAttributes">
        <div class="flex-1 @(sideRight ? "" : "text-end pe-4")">
            @if (!sideRight)
            {
                @ContentBlock
            }
        </div>
        <div class="flex flex-col items-center self-stretch">
            <div class="@DotClasses">
                @if (IconContent is not null)
                {
                    @IconContent
                }
                else
                {
                    <div class="h-2.5 w-2.5 rounded-[calc(var(--radius)*2)] @DotInnerFillClass"></div>
                }
            </div>
            <div class="@VerticalConnectorClasses" @key="@($"tl-a-{_index}-{ConnectorState}")"></div>
        </div>
        <div class="flex-1 @(sideRight ? "ps-4" : "")">
            @if (sideRight)
            {
                @ContentBlock
            }
        </div>
    </div>
}
else
{
    <div class="@VerticalCssClass" style="@AnimationStyle" role="listitem" aria-current="@ItemAriaCurrent" aria-label="@ItemAriaLabel" @attributes="AdditionalAttributes">
        <div class="flex flex-col items-center">
            <div class="@DotClasses">
                @if (IconContent is not null)
                {
                    @IconContent
                }
                else
                {
                    <div class="h-2.5 w-2.5 rounded-[calc(var(--radius)*2)] @DotInnerFillClass"></div>
                }
            </div>
            <div class="@VerticalConnectorClasses" @key="@($"tl-v-{_index}-{ConnectorState}")"></div>
        </div>
        <div class="ms-3 pb-6">
            @ContentBlock
        </div>
    </div>
}

@code {
    [CascadingParameter] public Timeline.TimelineContext? Context { get; set; }

    /// <summary>Icon slot. Named <c>IconContent</c> to avoid shadowing the <c>&lt;Icon&gt;</c> component.</summary>
    [Parameter] public RenderFragment? IconContent { get; set; }

    [Parameter] public string? Title { get; set; }
    [Parameter] public string? Description { get; set; }
    [Parameter] public string? Time { get; set; }

    /// <summary>
    /// Free-form content rendered in the item's body, after the structured
    /// Title / Description / Time (any of which may be omitted). Use this to
    /// compose richer entries — buttons, badges, avatars, nested markup — that
    /// the fixed fields can't express. Works in every orientation/layout.
    /// </summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>
    /// When set, marks this item as the "active" (current) item. When the
    /// parent <see cref="Timeline"/> has <c>Animated="true"</c>, this item's
    /// indicator pulses. If the parent also sets <c>ActiveIndex</c>, that
    /// value wins — use <c>IsActive</c> for static cases only.
    /// </summary>
    [Parameter] public bool IsActive { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private int _index;
    private Timeline? _registeredParent;

    protected override void OnInitialized()
    {
        _registeredParent = Context?.Parent;
        _registeredParent?.RegisterItem(this);
    }

    public void Dispose() => _registeredParent?.UnregisterItem(this);

    // Shared body — structured fields then optional free-form ChildContent.
    private RenderFragment ContentBlock => __builder =>
    {
        @if (!string.IsNullOrEmpty(Title))
        {
            <p class="text-sm font-medium text-foreground">@Title</p>
        }
        @if (!string.IsNullOrEmpty(Description))
        {
            <p class="text-xs text-muted-foreground">@Description</p>
        }
        @if (!string.IsNullOrEmpty(Time))
        {
            <p class="text-xs text-muted-foreground/70">@Time</p>
        }
        @if (ChildContent is not null)
        {
            <div class="mt-1">@ChildContent</div>
        }
    };

    private bool IsAnimated => Context?.Animated == true;
    private bool IsHorizontal => Context?.Orientation == Lumeo.Orientation.Horizontal;

    // a11y: mark the active item with aria-current="step" (mirrors StepsItem)
    // so the "you are here" state isn't conveyed by colour alone, and emit an
    // aria-label encoding completed/current/pending for screen readers.
    private string? ItemAriaCurrent => State == ProgressState.Active ? "step" : null;

    private string ItemAriaLabel
    {
        get
        {
            var label = !string.IsNullOrEmpty(Title) ? Title! : $"Item {_index + 1}";
            var state = State switch
            {
                ProgressState.Completed => " (completed)",
                ProgressState.Active => " (current)",
                _ => " (pending)"
            };
            return label + state;
        }
    }

    // Derived state, preferring the parent's ActiveIndex if set — otherwise
    // falling back to the legacy per-item IsActive flag.
    private enum ProgressState { Pending, Completed, Active }

    private ProgressState State
    {
        get
        {
            if (Context?.ActiveIndex is int idx)
            {
                if (_index < idx) return ProgressState.Completed;
                if (_index == idx) return ProgressState.Active;
                return ProgressState.Pending;
            }
            return IsActive ? ProgressState.Active : ProgressState.Pending;
        }
    }

    private string DotClasses
    {
        get
        {
            // When ActiveIndex is driving, "completed" items get a filled
            // primary background (like Steps completed), "active" uses the
            // bordered ring (readable as "you are here"), pending items fall
            // back to muted.
            string visual;
            if (Context?.ActiveIndex is not null)
            {
                visual = State switch
                {
                    ProgressState.Completed => "border-2 border-primary bg-primary text-primary-foreground",
                    ProgressState.Active => "border-2 border-primary bg-background text-primary",
                    _ => "border-2 border-muted bg-background text-muted-foreground"
                };
            }
            else
            {
                visual = "border-2 border-primary bg-background text-primary";
            }
            var baseClasses = $"flex h-8 w-8 shrink-0 items-center justify-center rounded-[calc(var(--radius)*2)] {visual}";
            return IsAnimated && State == ProgressState.Active ? $"{baseClasses} lumeo-steps-pulse" : baseClasses;
        }
    }

    // The inner filled dot (used when no IconContent is supplied). When
    // ActiveIndex drives progression we colour it to match the ring.
    private string DotInnerFillClass
    {
        get
        {
            if (Context?.ActiveIndex is null) return "bg-primary";
            return State switch
            {
                ProgressState.Completed => "bg-primary-foreground",
                ProgressState.Active => "bg-primary",
                _ => "bg-muted-foreground/50"
            };
        }
    }

    private string HorizontalConnectorClasses => BuildConnectorClasses(horizontal: true);
    private string VerticalConnectorClasses => BuildConnectorClasses(horizontal: false);

    // Three-state key used for @key so only the transitioning connector remounts.
    // "completed-drawing" / "completed-static" / "unwinding" / "pending"
    private string ConnectorState
    {
        get
        {
            if (Context?.ActiveIndex is not int current) return IsCompletedLegacy ? "completed-static" : "pending";

            var prev = Context.PreviousActiveIndex ?? current;
            var isBackward = current < prev;
            var isCompleted = _index < current;

            if (!isBackward && isCompleted && _index == current - 1) return "completed-drawing";
            if (isCompleted) return "completed-static";
            if (isBackward && _index == current) return "unwinding";
            return "pending";
        }
    }

    // Legacy completed state for the no-ActiveIndex path.
    private bool IsCompletedLegacy => Context?.ActiveIndex is null && false;

    private string BuildConnectorClasses(bool horizontal)
    {
        var baseLayout = horizontal ? "mx-2 mt-4 h-px flex-1" : "my-1 w-px flex-1";

        if (!IsAnimated)
        {
            // Static: colour based on ActiveIndex completion state.
            var staticColor = (Context?.ActiveIndex is int si && _index < si) ? "bg-primary" : "bg-border";
            return $"{baseLayout} {staticColor}";
        }

        // Legacy no-ActiveIndex animated path — always draw in on mount.
        if (Context?.ActiveIndex is null)
        {
            var drawClass = horizontal ? "lumeo-steps-line-draw-x" : "lumeo-steps-line-draw-y";
            return $"{baseLayout} bg-border {drawClass}";
        }

        // ActiveIndex-driven: animate only the transitioning connector.
        var state = ConnectorState;
        return state switch
        {
            "completed-drawing" => $"{baseLayout} bg-primary " + (horizontal ? "lumeo-steps-line-draw-x" : "lumeo-steps-line-draw-y"),
            "completed-static" => $"{baseLayout} bg-primary",
            // Force bg-primary so the unwinding line is visible (otherwise the
            // retracting line is bg-border grey — invisible on muted bg).
            "unwinding" => $"{baseLayout} bg-primary " + (horizontal ? "lumeo-steps-line-unwind-x" : "lumeo-steps-line-unwind-y"),
            _ => $"{baseLayout} bg-border"
        };
    }

    private string VerticalCssClass
    {
        get
        {
            var baseClasses = Cx.Merge("flex flex-row", Class);
            return IsAnimated ? $"{baseClasses} lumeo-timeline-enter-vertical" : baseClasses;
        }
    }

    private string AlternateCssClass
    {
        get
        {
            var baseClasses = Cx.Merge("flex flex-row items-stretch", Class);
            return IsAnimated ? $"{baseClasses} lumeo-timeline-enter-vertical" : baseClasses;
        }
    }

    private string HorizontalCssClass
    {
        get
        {
            var baseClasses = Cx.Merge("flex flex-1 flex-row last:flex-initial", Class);
            return IsAnimated ? $"{baseClasses} lumeo-timeline-enter-horizontal" : baseClasses;
        }
    }

    private string? AnimationStyle =>
        IsAnimated ? $"animation-delay: {_index * 80}ms;" : null;
}
